import { fromNeverthrowError, outputAndExit } from '@/cli/output';

import type { GlobalFlags } from '@/types';
import { getWallet } from '@/wallet';

export async function getWalletOrExit(flags: GlobalFlags) {
  const walletResult = await getWallet();

  if (walletResult.isErr()) {
    outputAndExit(fromNeverthrowError(walletResult, 'WALLET_ERROR'), flags);
  }

  return walletResult.value;
}
